import {
  colors,
  durationMs,
  easings,
  font,
  scale,
  shadowLayerCss,
  shadows,
} from "./model.mjs";

const HEADER = `/**
 * Houston design tokens — typed constants for TypeScript surfaces (SDK, web).
 * AUTO-GENERATED by @houston/design-tokens. Do NOT edit by hand.
 * Rebuild: pnpm --filter @houston/design-tokens build
 */`;

// A bare object literal (no `as const`), so it can be a top-level export value
// or nested inside `color`. Indent controls nesting depth.
const lit = (entries, indent = "  ") =>
  `{\n${entries.map(([k, v]) => `${indent}${JSON.stringify(k)}: ${v},`).join("\n")}\n${indent.slice(2)}}`;

const strLit = (entries, indent) =>
  lit(
    entries.map(({ name, value }) => [name, JSON.stringify(value)]),
    indent,
  );

export function buildTs(light, dark) {
  const durations = scale(light, "duration");
  const parts = [
    HEADER,
    "",
    'export type ThemeName = "light" | "dark";',
    "",
    "/** Semantic colours, keyed by the same names as the --ht-* CSS variables. */",
    `export const color = {\n  light: ${strLit(colors(light), "    ")},\n  dark: ${strLit(
      colors(dark),
      "    ",
    )},\n} as const;`,
    "",
    `export const space = ${strLit(scale(light, "space"))} as const;`,
    "",
    `export const radius = ${strLit(scale(light, "radius"))} as const;`,
    "",
    `export const fontFamily = ${strLit(font(light, "family"))} as const;`,
    "",
    `export const fontWeight = ${lit(font(light, "weight").map((e) => [e.name, String(e.value)]))} as const;`,
    "",
    `export const fontSize = ${strLit(font(light, "size"))} as const;`,
    "",
    "/** CSS duration strings (e.g. transition/animation shorthands). */",
    `export const duration = ${strLit(durations)} as const;`,
    "",
    "/** Durations in milliseconds, for JS-driven animation. */",
    `export const durationMs = ${lit(durations.map((e) => [e.name, String(durationMs(e.value))]))} as const;`,
    "",
    "/** Cubic-bezier control points [x1, y1, x2, y2]. */",
    `export const easing = ${lit(easings(light).map((e) => [e.name, `[${e.value.join(", ")}]`]))} as const;`,
    "",
    "/** Ready-to-use CSS box-shadow strings. */",
    `export const shadow = ${lit(
      shadows(light).map((s) => [
        s.name,
        JSON.stringify(s.layers.map(shadowLayerCss).join(", ")),
      ]),
    )} as const;`,
    "",
  ];
  return parts.join("\n");
}
